//! OATH — a sworn, bounded commitment that gates CONDUCT.
//!
//! Where a qspec gates QUALITY ("does the artifact actually work?", proven by a
//! probe), an **oath** gates **conduct** ("under what bounded commitment may
//! this be admitted?"). An oath declares a human commitment string, the caps the
//! commitment permits, and an optional TTL ceiling and signer DID. On admission
//! (`delegate --oath`), the requested caps must be a subset of the oath's
//! `max_caps` and the requested TTL must not exceed `ttl_max_secs` (when set);
//! otherwise admission is DENIED and no grant is minted. On success the oath
//! terms (plus proof metadata) are bound into the minted grant as its `fct`
//! ("facts"), so the grant cryptographically *carries* the commitment it was
//! admitted under, and that commitment bounds the grant's scope.
//!
//! # Two forms of oath
//!
//! 1. **Signed oath-token** (preferred) — a UCAN signed by *the swearer's own
//!    key*, so the grant carries CRYPTOGRAPHIC PROOF of who swore it, not merely
//!    JSON text stapled in by root. A Ulysses oath is self-issued and
//!    self-audienced (`iss == aud`): an irrevocable precommitment the swearer
//!    binds upon itself. Shape:
//!    ```text
//!    iss = swearer DID
//!    aud = agent DID            (Ulysses: iss == aud)
//!    att = [{ can: "oath/uphold", with: "agent:self:<id>" }]
//!    fct = { oath, max_caps, ttl_max_secs?, sworn_by? }
//!    sig = the swearer's signature
//!    ```
//!    A co-signed oath is a 2-link chain: the spawner-imposed token is the `prf`
//!    of the agent's acceptance token; `verify_chain` validates the whole chain.
//!
//! 2. **Raw JSON** (back-compat) — an UNSIGNED oathspec. Behaves as before, but
//!    the grant records `signed:false`: there is no cryptographic swearer.
//!
//! Contract (the oath *terms*, whether raw JSON or a token's `fct`):
//! ```json
//! { "oath": "I serve the spawner's intent, stay within my caps, and do not exfiltrate.",
//!   "max_caps": ["net"], "ttl_max_secs": 3600, "sworn_by": "did:key:..." }
//! ```
//! `oath` (human commitment) and `max_caps` (permitted caps) are required;
//! `ttl_max_secs` and `sworn_by` are optional.

use std::path::Path;

use a0n_auth::{check_capability, Capability, RevocationSet};
use serde::{Deserialize, Serialize};
use serde_json::Value;

/// The capability a signed oath-token must grant on its leaf: a sworn promise to
/// uphold the oath. Matched with the wildcard resource `agent:self:*` so any
/// `agent:self:<id>` resource satisfies it.
pub const OATH_UPHOLD_CAN: &str = "oath/uphold";
const OATH_UPHOLD_WITH_PREFIX: &str = "agent:self:";

/// A sworn, bounded conduct commitment.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct OathSpec {
    /// The human commitment string. Required, non-empty.
    pub oath: String,
    /// The capabilities this oath permits. Requested caps must be a subset.
    pub max_caps: Vec<String>,
    /// Optional TTL ceiling in seconds. When set, the requested grant TTL must
    /// not exceed it.
    #[serde(skip_serializing_if = "Option::is_none", default)]
    pub ttl_max_secs: Option<i64>,
    /// Optional DID of the swearer. For a raw-JSON oath this is documentation /
    /// provenance only; for a signed token the *cryptographic* swearer is the
    /// token's `iss` (recorded separately as proof metadata).
    #[serde(skip_serializing_if = "Option::is_none", default)]
    pub sworn_by: Option<String>,
}

impl OathSpec {
    /// Parse an oathspec from JSON text, checking well-formedness. This is the
    /// shape of both a raw-JSON oath file *and* a signed token's `fct`.
    pub fn parse(text: &str) -> Result<OathSpec, String> {
        let spec: OathSpec =
            serde_json::from_str(text).map_err(|e| format!("invalid oath JSON: {e}"))?;
        spec.validate()?;
        Ok(spec)
    }

    /// Parse an oathspec from an already-decoded JSON `Value` (a token's `fct`).
    pub fn from_value(v: &Value) -> Result<OathSpec, String> {
        let spec: OathSpec = serde_json::from_value(v.clone())
            .map_err(|e| format!("oath token fct is not a valid oath spec: {e}"))?;
        spec.validate()?;
        Ok(spec)
    }

    fn validate(&self) -> Result<(), String> {
        if self.oath.trim().is_empty() {
            return Err("oath: 'oath' commitment string must not be empty".to_string());
        }
        if self.max_caps.is_empty() {
            return Err(
                "oath: 'max_caps' must declare at least one permitted capability".to_string(),
            );
        }
        if let Some(ttl) = self.ttl_max_secs {
            if ttl <= 0 {
                return Err("oath: 'ttl_max_secs' must be positive when set".to_string());
            }
        }
        Ok(())
    }

    /// The oath terms as a JSON Value, suitable for binding into a grant's `fct`.
    pub fn to_fact(&self) -> Value {
        serde_json::to_value(self).unwrap_or(Value::Null)
    }
}

/// A swearer's commitment after admission verification: the oath terms plus
/// proof metadata about *who* swore it and *how*.
#[derive(Debug, Clone)]
pub struct AdmittedOath {
    /// The verified oath terms (caps/ttl bound, human commitment). For a
    /// multi-link chain these are the LEAF (most-attenuated / actually-sworn)
    /// terms — the child is held to the tightest oath in the chain.
    pub spec: OathSpec,
    /// Whether the oath was a cryptographically-signed token (vs raw JSON).
    pub signed: bool,
    /// The DID that cryptographically swore the oath (the leaf token's `iss`),
    /// or `None` for an unsigned raw-JSON oath.
    pub swearer: Option<String>,
    /// Whether this is a Ulysses oath: self-issued and self-audienced
    /// (`iss == aud`) — an irrevocable precommitment the swearer binds on itself.
    pub ulysses: bool,
    /// Number of links in the verified delegation chain (1 for a Ulysses /
    /// single-link token, >= 2 for a co-signed/imposed chain). `None` for an
    /// unsigned raw-JSON oath (no chain to count).
    pub chain_depth: Option<usize>,
    /// For a multi-link (co-signed/imposed) chain, the DID of the immediate
    /// parent (the issuer that IMPOSED the oath on the leaf). `None` for a
    /// single-link token or an unsigned raw-JSON oath.
    pub imposed_by: Option<String>,
}

impl AdmittedOath {
    /// The fact to bind into the minted grant: the oath terms PLUS proof
    /// metadata recording who cryptographically swore it. The grant thus carries
    /// proof of provenance, not just the commitment text.
    pub fn to_fact(&self) -> Value {
        let mut fct = self.spec.to_fact();
        if let Value::Object(map) = &mut fct {
            map.insert(
                "sworn_by".to_string(),
                match &self.swearer {
                    Some(did) => Value::String(did.clone()),
                    None => Value::Null,
                },
            );
            map.insert("ulysses".to_string(), Value::Bool(self.ulysses));
            map.insert("signed".to_string(), Value::Bool(self.signed));
            // For a co-signed/imposed chain (more than one link), record the
            // chain depth and the immediate parent that imposed the oath, so
            // the grant carries proof that it was attenuated down a delegation
            // tree (not merely self-bound).
            if let (Some(depth), Some(parent)) = (self.chain_depth, &self.imposed_by) {
                if depth > 1 {
                    map.insert(
                        "oath_chain_depth".to_string(),
                        Value::Number(serde_json::Number::from(depth)),
                    );
                    map.insert("imposed_by".to_string(), Value::String(parent.clone()));
                }
            }
        }
        fct
    }
}

/// True if `s` has the shape of a UCAN: exactly three non-empty base64url
/// segments separated by '.'. Raw JSON (which starts with '{' / whitespace) and
/// arbitrary text fail this, so detection is unambiguous against the oath JSON
/// contract. We check shape only; cryptographic validity is decided by
/// [`admit`] via `verify_chain`.
pub fn looks_like_token(s: &str) -> bool {
    let s = s.trim();
    let parts: Vec<&str> = s.split('.').collect();
    if parts.len() != 3 {
        return false;
    }
    let is_b64url = |seg: &str| {
        !seg.is_empty()
            && seg
                .bytes()
                .all(|b| b.is_ascii_alphanumeric() || b == b'-' || b == b'_')
    };
    parts.iter().all(|p| is_b64url(p))
}

/// True iff the leaf's `att` grants `oath/uphold` on some `agent:self:<id>`
/// resource — i.e. it is genuinely a *sworn oath*. We locate a candidate granted
/// capability (uphold action on a self-resource) and then confirm it with
/// `check_capability` (the authoritative matcher), so the decision flows through
/// the same matching used everywhere else.
fn grants_oath_uphold(granted: &[Capability]) -> bool {
    granted.iter().any(|g| {
        if g.can != OATH_UPHOLD_CAN {
            return false;
        }
        if !g.with.starts_with(OATH_UPHOLD_WITH_PREFIX) {
            return false;
        }
        // Confirm via the authoritative capability matcher against this exact
        // (concrete) self-resource.
        let required = Capability {
            can: OATH_UPHOLD_CAN.to_string(),
            with: g.with.clone(),
            constraints: None,
        };
        check_capability(granted, &required)
    })
}

/// Enforce that a `child` oath does not permit WEAKER terms than the `parent`
/// oath that imposed it: the child's permitted caps must be a SUBSET of the
/// parent's, and (when the parent sets a ttl ceiling) the child's ttl ceiling
/// must be set and must be `<=` the parent's. An unbounded child under a bounded
/// parent is DENIED — the child cannot silently widen the ttl. DENY (Err) names
/// the offending caps / ttl. This is the OATH-SUBSET rule, applied between every
/// consecutive (child, parent) pair of a co-signed/imposed chain.
fn attenuates(child: &OathSpec, parent: &OathSpec) -> Result<(), String> {
    let escalated: Vec<&String> = child
        .max_caps
        .iter()
        .filter(|c| !parent.max_caps.iter().any(|p| p == *c))
        .collect();
    if !escalated.is_empty() {
        let bad = escalated
            .iter()
            .map(|c| c.as_str())
            .collect::<Vec<_>>()
            .join(",");
        return Err(format!(
            "oath escalation: child oath permits [{bad}] beyond parent oath [{}]",
            parent.max_caps.join(",")
        ));
    }
    if let Some(parent_ttl) = parent.ttl_max_secs {
        match child.ttl_max_secs {
            Some(child_ttl) if child_ttl <= parent_ttl => {}
            Some(child_ttl) => {
                return Err(format!(
                    "oath escalation: child oath permits ttl {child_ttl}s beyond parent oath \
                     ttl {parent_ttl}s"
                ));
            }
            None => {
                return Err(format!(
                    "oath escalation: child oath permits [unbounded ttl] beyond parent oath \
                     ttl {parent_ttl}s"
                ));
            }
        }
    }
    Ok(())
}

/// Admit a signed oath-token. DENIES (Err) on an invalid/expired/revoked
/// signature, a missing `oath/uphold` capability on the leaf, a malformed `fct`,
/// or — for a co-signed/imposed (multi-link) chain — an oath ESCALATION where a
/// child link permits weaker terms than the parent that imposed it. On success
/// returns the verified LEAF terms (the most-attenuated, actually-sworn terms)
/// plus proof metadata (the swearer DID and the Ulysses flag come from the
/// *cryptographically-verified* leaf; the chain depth + imposer come from the
/// verified chain).
///
/// Note: this verifies the chain, reads EACH link's terms, and enforces the
/// oath-subset attenuation BETWEEN links; the caps-subset + ttl bound on the
/// leaf terms against the requested grant is enforced separately by [`check`] /
/// [`enforce`].
pub fn admit_token(token: &str, revocations: &RevocationSet) -> Result<AdmittedOath, String> {
    let result = a0n_auth::delegation::verify_chain(token, Some(revocations), None);
    if !result.valid {
        return Err(format!(
            "oath-token signature/chain invalid: {}",
            result.error.unwrap_or_else(|| "unknown".to_string())
        ));
    }
    // The leaf is the first link of the chain (leaf -> root). Its `iss` is the
    // swearer; its `att` must grant `oath/uphold`; its `fct` carries the terms.
    let leaf = result
        .chain
        .first()
        .ok_or_else(|| "oath-token verified but produced an empty chain".to_string())?;

    if !grants_oath_uphold(&leaf.att) {
        return Err(format!(
            "oath-token does not grant '{OATH_UPHOLD_CAN}' on '{OATH_UPHOLD_WITH_PREFIX}<id>'; \
             it is not a sworn oath"
        ));
    }

    let fct = leaf
        .fct
        .as_ref()
        .ok_or_else(|| "oath-token carries no fct (oath terms)".to_string())?;
    let spec = OathSpec::from_value(fct)?;

    let swearer = leaf.iss.clone();
    let ulysses = leaf.iss == leaf.aud;
    let chain_depth = result.chain.len();

    // Co-signed / imposed chain (more than one link): oaths must ATTENUATE down
    // the delegation tree. Read EACH link's `fct` oath terms and enforce the
    // oath-subset rule between consecutive links — the leaf (chain[0]) is the
    // child/accepted, the next link (chain[1]) is the parent/imposed, and so on
    // toward the root. A child must not accept WEAKER terms than its parent
    // imposed. A single-link (Ulysses) token has nothing to attenuate against.
    let mut imposed_by: Option<String> = None;
    if chain_depth > 1 {
        // Parse every link's oath terms once, leaf-first.
        let mut specs: Vec<OathSpec> = Vec::with_capacity(chain_depth);
        for (i, link) in result.chain.iter().enumerate() {
            let link_fct = link.fct.as_ref().ok_or_else(|| {
                format!("oath chain link {i} (iss {}) carries no fct (oath terms)", link.iss)
            })?;
            specs.push(OathSpec::from_value(link_fct)?);
        }
        // Enforce attenuation between each (child, parent) pair: chain[i] is the
        // child, chain[i+1] is the parent that imposed on it.
        for i in 0..specs.len() - 1 {
            attenuates(&specs[i], &specs[i + 1])
                .map_err(|why| format!("admission denied: {why}"))?;
        }
        // The immediate parent (chain[1]) is who imposed the oath on the leaf.
        imposed_by = Some(result.chain[1].iss.clone());
    }

    Ok(AdmittedOath {
        spec,
        signed: true,
        swearer: Some(swearer),
        ulysses,
        chain_depth: Some(chain_depth),
        imposed_by,
    })
}

/// Admit a raw-JSON (UNSIGNED) oath. Behaves as before: parse + validate the
/// terms. There is no cryptographic swearer, so `signed:false`, `swearer:None`,
/// `ulysses:false`.
pub fn admit_json(text: &str) -> Result<AdmittedOath, String> {
    let spec = OathSpec::parse(text)?;
    Ok(AdmittedOath {
        spec,
        signed: false,
        swearer: None,
        ulysses: false,
        chain_depth: None,
        imposed_by: None,
    })
}

/// Admit an oath from raw text, accepting EITHER a signed oath-token OR raw JSON
/// (back-compat). Detection is by shape: a UCAN is three base64url segments
/// separated by '.'. A signed token has its swearer's signature verified via
/// `verify_chain`; raw JSON is treated as unsigned. This does NOT enforce the
/// caps/ttl bound — call [`enforce`] (or [`check`]) on the result for that.
pub fn admit(text: &str, revocations: &RevocationSet) -> Result<AdmittedOath, String> {
    if looks_like_token(text) {
        admit_token(text.trim(), revocations)
    } else {
        admit_json(text)
    }
}

/// Load an oath from a file (either form) and admit it. Used by `delegate
/// --oath` and `oath verify`.
pub fn load(path: impl AsRef<Path>, revocations: &RevocationSet) -> Result<AdmittedOath, String> {
    let path = path.as_ref();
    let text = std::fs::read_to_string(path)
        .map_err(|e| format!("could not read oath '{}': {e}", path.display()))?;
    admit(&text, revocations)
}

/// Admission check: DENY (Err) if the requested caps are not a subset of the
/// oath's `max_caps`, or if `ttl_max_secs` is set and the requested TTL exceeds
/// it. On success, returns the oath terms JSON Value (terms only — proof
/// metadata is added by [`AdmittedOath::to_fact`]).
pub fn check(spec: &OathSpec, requested_caps: &[String], ttl_secs: i64) -> Result<Value, String> {
    let exceeded: Vec<&String> = requested_caps
        .iter()
        .filter(|c| !spec.max_caps.iter().any(|m| m == *c))
        .collect();
    if !exceeded.is_empty() {
        let bad = exceeded
            .iter()
            .map(|c| c.as_str())
            .collect::<Vec<_>>()
            .join(",");
        return Err(format!(
            "requested caps [{bad}] exceed the oath (oath permits [{}])",
            spec.max_caps.join(",")
        ));
    }
    if let Some(max) = spec.ttl_max_secs {
        if ttl_secs > max {
            return Err(format!(
                "requested ttl {ttl_secs}s exceeds the oath ceiling ({max}s)"
            ));
        }
    }
    Ok(spec.to_fact())
}

/// Enforce the caps-subset + ttl bound on an already-admitted oath, returning
/// the grant `fct` (verified terms PLUS proof metadata) on success. This is what
/// `delegate --oath` binds into the minted grant.
pub fn enforce(
    admitted: &AdmittedOath,
    requested_caps: &[String],
    ttl_secs: i64,
) -> Result<Value, String> {
    check(&admitted.spec, requested_caps, ttl_secs)?;
    Ok(admitted.to_fact())
}

/// Validate an oath file (either form) for the CLI (`oath verify`). The bound
/// checks in [`check`] require a request (caps + ttl) and so cannot be applied
/// to a file in isolation; this admits (verifying the signature for a token) and
/// returns the proof + terms for display.
pub fn verify(
    path: impl AsRef<Path>,
    revocations: &RevocationSet,
) -> Result<AdmittedOath, String> {
    load(path, revocations)
}

#[cfg(test)]
mod tests {
    use super::*;
    use a0n_auth::ucan::{issue, parse};
    use a0n_auth::{Capability, IssueOptions, Keypair};

    fn reference_json() -> &'static str {
        r#"{ "oath": "I serve the spawner's intent, stay within my caps, and do not exfiltrate.",
             "max_caps": ["net"], "ttl_max_secs": 3600, "sworn_by": "did:key:zABC" }"#
    }

    /// Mint a signed oath-token. `iss == aud == swearer` makes it Ulysses.
    fn mint_oath_token(swearer: &Keypair, audience: &str, terms_fct: Value) -> String {
        let cap = Capability {
            can: OATH_UPHOLD_CAN.to_string(),
            with: "agent:self:abc123".to_string(),
            constraints: None,
        };
        let opts = IssueOptions {
            facts: Some(terms_fct),
            ..Default::default()
        };
        issue(swearer, audience, &[cap], 3600, &opts).unwrap()
    }

    fn terms(oath: &str, caps: &[&str], ttl: Option<i64>) -> Value {
        let mut m = serde_json::json!({
            "oath": oath,
            "max_caps": caps,
        });
        if let Some(t) = ttl {
            m["ttl_max_secs"] = serde_json::json!(t);
        }
        m
    }

    /// Mint a co-signed (2-link) oath chain: the `parent` IMPOSES an oath
    /// (iss=parent, aud=child) and the `child` ACCEPTS it (iss=child, aud=child,
    /// prf=[parent_token]). Returns the leaf token (the child's acceptance), with
    /// the parent token spliced in as its `prf` so `verify_chain` walks both.
    fn mint_cosigned_chain(
        parent: &Keypair,
        child: &Keypair,
        parent_terms: Value,
        child_terms: Value,
    ) -> String {
        let cap = Capability {
            can: OATH_UPHOLD_CAN.to_string(),
            with: "agent:self:abc123".to_string(),
            constraints: None,
        };
        // Parent imposes the oath on the child (iss=parent, aud=child).
        let imposed = issue(
            parent,
            child.did(),
            &[cap.clone()],
            3600,
            &IssueOptions {
                facts: Some(parent_terms),
                ..Default::default()
            },
        )
        .unwrap();
        // Child accepts (iss=child, aud=child = self), proving the imposed token.
        issue(
            child,
            child.did(),
            &[cap],
            3600,
            &IssueOptions {
                facts: Some(child_terms),
                proofs: vec![imposed],
                ..Default::default()
            },
        )
        .unwrap()
    }

    // ---- parser well-formedness -------------------------------------------

    #[test]
    fn parses_full_oath() {
        let spec = OathSpec::parse(reference_json()).unwrap();
        assert!(spec.oath.contains("do not exfiltrate"));
        assert_eq!(spec.max_caps, vec!["net".to_string()]);
        assert_eq!(spec.ttl_max_secs, Some(3600));
        assert_eq!(spec.sworn_by.as_deref(), Some("did:key:zABC"));
    }

    #[test]
    fn optional_fields_default() {
        let spec =
            OathSpec::parse(r#"{ "oath": "stay bounded", "max_caps": ["net","fs"] }"#).unwrap();
        assert!(spec.ttl_max_secs.is_none());
        assert!(spec.sworn_by.is_none());
    }

    #[test]
    fn empty_oath_string_rejected() {
        let err = OathSpec::parse(r#"{ "oath": "   ", "max_caps": ["net"] }"#).unwrap_err();
        assert!(err.contains("commitment string"), "got: {err}");
    }

    #[test]
    fn empty_max_caps_rejected() {
        let err = OathSpec::parse(r#"{ "oath": "x", "max_caps": [] }"#).unwrap_err();
        assert!(err.contains("max_caps"), "got: {err}");
    }

    #[test]
    fn non_positive_ttl_rejected() {
        let err = OathSpec::parse(r#"{ "oath": "x", "max_caps": ["net"], "ttl_max_secs": 0 }"#)
            .unwrap_err();
        assert!(err.contains("ttl_max_secs"), "got: {err}");
    }

    #[test]
    fn malformed_json_rejected() {
        assert!(OathSpec::parse("{ not json").is_err());
    }

    // ---- caps subset check -------------------------------------------------

    #[test]
    fn caps_subset_passes() {
        let spec = OathSpec::parse(r#"{ "oath": "x", "max_caps": ["net","fs"] }"#).unwrap();
        let fct = check(&spec, &["net".to_string()], 60).unwrap();
        // The returned fact carries the oath commitment.
        assert_eq!(fct["oath"], "x");
        assert_eq!(fct["max_caps"][0], "net");
    }

    #[test]
    fn caps_exact_match_passes() {
        let spec = OathSpec::parse(r#"{ "oath": "x", "max_caps": ["net","fs"] }"#).unwrap();
        assert!(check(&spec, &["net".to_string(), "fs".to_string()], 60).is_ok());
    }

    #[test]
    fn caps_violation_denied() {
        let spec = OathSpec::parse(r#"{ "oath": "x", "max_caps": ["net"] }"#).unwrap();
        let err = check(
            &spec,
            &["fs".to_string(), "net".to_string(), "exec".to_string()],
            60,
        )
        .unwrap_err();
        assert!(err.contains("exceed the oath"), "got: {err}");
        assert!(err.contains("fs"), "should name the offending caps: {err}");
        assert!(err.contains("exec"), "should name the offending caps: {err}");
    }

    #[test]
    fn empty_request_always_within_oath() {
        let spec = OathSpec::parse(r#"{ "oath": "x", "max_caps": ["net"] }"#).unwrap();
        assert!(check(&spec, &[], 60).is_ok());
    }

    // ---- ttl ceiling check -------------------------------------------------

    #[test]
    fn ttl_within_ceiling_passes() {
        let spec = OathSpec::parse(r#"{ "oath": "x", "max_caps": ["net"], "ttl_max_secs": 3600 }"#)
            .unwrap();
        assert!(check(&spec, &["net".to_string()], 3600).is_ok());
        assert!(check(&spec, &["net".to_string()], 1800).is_ok());
    }

    #[test]
    fn ttl_over_ceiling_denied() {
        let spec = OathSpec::parse(r#"{ "oath": "x", "max_caps": ["net"], "ttl_max_secs": 3600 }"#)
            .unwrap();
        let err = check(&spec, &["net".to_string()], 7200).unwrap_err();
        assert!(err.contains("ttl"), "got: {err}");
        assert!(err.contains("3600"), "should name the ceiling: {err}");
    }

    #[test]
    fn no_ttl_ceiling_allows_any_ttl() {
        let spec = OathSpec::parse(r#"{ "oath": "x", "max_caps": ["net"] }"#).unwrap();
        assert!(check(&spec, &["net".to_string()], i64::MAX).is_ok());
    }

    // ---- caps checked before ttl is irrelevant to ordering; both must hold --

    #[test]
    fn caps_violation_denied_even_when_ttl_ok() {
        let spec = OathSpec::parse(r#"{ "oath": "x", "max_caps": ["net"], "ttl_max_secs": 3600 }"#)
            .unwrap();
        assert!(check(&spec, &["fs".to_string()], 60).is_err());
    }

    // ---- to_fact round-trips ----------------------------------------------

    #[test]
    fn to_fact_carries_full_oath() {
        let spec = OathSpec::parse(reference_json()).unwrap();
        let fct = spec.to_fact();
        assert_eq!(
            fct["oath"],
            "I serve the spawner's intent, stay within my caps, and do not exfiltrate."
        );
        assert_eq!(fct["ttl_max_secs"], 3600);
        assert_eq!(fct["sworn_by"], "did:key:zABC");
    }

    // ---- end-to-end: a minted grant carries the oath as its `fct` ----------
    //
    // Mirrors what `delegate --oath` does for a RAW-JSON oath: gate with
    // check(), then mint with IssueOptions { facts: Some(oath_json) }.
    #[test]
    fn minted_grant_fct_equals_oath() {
        let spec = OathSpec::parse(reference_json()).unwrap();
        let fct = check(&spec, &["net".to_string()], 3600).expect("within oath");

        let root = Keypair::generate();
        let cap = Capability {
            can: "exec/run".to_string(),
            with: "plugin:ok".to_string(),
            constraints: Some(serde_json::json!({ "caps": ["net"] })),
        };
        let opts = IssueOptions {
            facts: Some(fct.clone()),
            ..Default::default()
        };
        let token = issue(&root, root.did(), &[cap], 3600, &opts).unwrap();

        let parsed = parse(&token).unwrap();
        let bound = parsed.payload.fct.expect("grant must carry an fct");
        assert_eq!(bound, fct, "grant fct must equal the oath JSON");
        assert_eq!(
            bound["oath"],
            "I serve the spawner's intent, stay within my caps, and do not exfiltrate."
        );
        assert_eq!(bound["max_caps"][0], "net");
    }

    // ---- token-vs-JSON detection ------------------------------------------

    #[test]
    fn detects_raw_json_is_not_a_token() {
        assert!(!looks_like_token(reference_json()));
        assert!(!looks_like_token(r#"{ "oath": "x", "max_caps": ["net"] }"#));
        assert!(!looks_like_token("  { \"oath\": \"x\" }  "));
    }

    #[test]
    fn detects_token_shape() {
        let kp = Keypair::generate();
        let token = mint_oath_token(&kp, kp.did(), terms("uphold", &["net"], None));
        assert!(looks_like_token(&token));
        // exactly 3 base64url segments
        assert_eq!(token.split('.').count(), 3);
    }

    #[test]
    fn detects_wrong_segment_count_is_not_a_token() {
        assert!(!looks_like_token("a.b"));
        assert!(!looks_like_token("a.b.c.d"));
        assert!(!looks_like_token("just-one-segment"));
        assert!(!looks_like_token("a..c")); // empty middle segment
    }

    // ---- (a) Ulysses self-signed oath-token verifies + admits + proof ------

    #[test]
    fn ulysses_token_verifies_and_admits_with_proof() {
        let swearer = Keypair::generate();
        // Ulysses: iss == aud == the swearer's own DID.
        let token = mint_oath_token(
            &swearer,
            swearer.did(),
            terms("I bind myself to my caps", &["net", "fs"], Some(3600)),
        );

        let rev = RevocationSet::new();
        let admitted = admit(&token, &rev).expect("Ulysses oath-token must admit");
        assert!(admitted.signed, "must be recognized as signed");
        assert!(admitted.ulysses, "iss == aud must be Ulysses");
        assert_eq!(
            admitted.swearer.as_deref(),
            Some(swearer.did()),
            "swearer must be the token's iss"
        );

        // enforce caps/ttl bound, then the grant fct must carry the proof.
        let fct = enforce(&admitted, &["net".to_string()], 3600).expect("within oath");
        assert_eq!(fct["signed"], true);
        assert_eq!(fct["ulysses"], true);
        assert_eq!(fct["sworn_by"], swearer.did());
        assert_eq!(fct["oath"], "I bind myself to my caps");
        assert_eq!(fct["max_caps"][0], "net");

        // And the grant minted with that fct round-trips the crypto proof.
        let root = Keypair::generate();
        let cap = Capability {
            can: "exec/run".to_string(),
            with: "plugin:ok".to_string(),
            constraints: Some(serde_json::json!({ "caps": ["net"] })),
        };
        let grant = issue(
            &root,
            root.did(),
            &[cap],
            3600,
            &IssueOptions {
                facts: Some(fct.clone()),
                ..Default::default()
            },
        )
        .unwrap();
        let bound = parse(&grant).unwrap().payload.fct.expect("grant carries fct");
        assert_eq!(bound["sworn_by"], swearer.did());
        assert_eq!(bound["ulysses"], true);
        assert_eq!(bound["signed"], true);
    }

    #[test]
    fn co_signed_chain_is_not_ulysses_but_admits() {
        // Spawner imposes an oath on the agent: spawner -> agent.
        let spawner = Keypair::generate();
        let agent = Keypair::generate();
        let imposed = mint_oath_token(
            &spawner,
            agent.did(),
            terms("serve the spawner", &["net"], Some(3600)),
        );

        let rev = RevocationSet::new();
        let admitted = admit(&imposed, &rev).expect("imposed oath admits");
        assert!(admitted.signed);
        assert!(!admitted.ulysses, "iss != aud is not Ulysses");
        assert_eq!(admitted.swearer.as_deref(), Some(spawner.did()));
        let fct = enforce(&admitted, &["net".to_string()], 3600).unwrap();
        assert_eq!(fct["ulysses"], false);
        assert_eq!(fct["signed"], true);
        assert_eq!(fct["sworn_by"], spawner.did());
    }

    // ---- (b) a tampered/forged signature is DENIED -------------------------

    #[test]
    fn tampered_signature_is_denied() {
        let swearer = Keypair::generate();
        let token = mint_oath_token(&swearer, swearer.did(), terms("x", &["net"], None));

        // Flip a char in the payload segment so the signature no longer matches.
        let mut parts: Vec<String> = token.split('.').map(String::from).collect();
        let mut chars: Vec<char> = parts[1].chars().collect();
        chars[0] = if chars[0] == 'A' { 'B' } else { 'A' };
        parts[1] = chars.into_iter().collect();
        let forged = parts.join(".");

        let rev = RevocationSet::new();
        let err = admit(&forged, &rev).unwrap_err();
        assert!(
            err.contains("invalid") || err.contains("signature"),
            "forged signature must be denied: {err}"
        );
    }

    #[test]
    fn forged_swearer_did_is_denied() {
        // Take a real token's payload (iss = victim) and re-sign with attacker's
        // key; the iss DID no longer matches the signing key -> signature fails.
        let victim = Keypair::generate();
        let attacker = Keypair::generate();
        let good = mint_oath_token(&victim, victim.did(), terms("x", &["net"], None));
        // Re-sign the same signing_input bytes with the attacker key, keeping the
        // victim's iss in the payload: verify against iss (victim) must fail.
        let parts: Vec<&str> = good.split('.').collect();
        let signing_input = format!("{}.{}", parts[0], parts[1]);
        // Build a token whose sig is the attacker's over the victim payload.
        let attacker_sig_token = {
            // We can't access the private signer directly; instead mint a fresh
            // attacker token and splice its signature onto the victim payload.
            let attacker_tok =
                mint_oath_token(&attacker, attacker.did(), terms("x", &["net"], None));
            let asig = attacker_tok.split('.').nth(2).unwrap();
            format!("{signing_input}.{asig}")
        };
        let rev = RevocationSet::new();
        assert!(
            admit(&attacker_sig_token, &rev).is_err(),
            "a swearer DID that doesn't match the signature must be denied"
        );
    }

    #[test]
    fn token_without_uphold_capability_is_denied() {
        // A validly-signed token, but its capability is not oath/uphold.
        let swearer = Keypair::generate();
        let cap = Capability {
            can: "exec/run".to_string(),
            with: "plugin:bw".to_string(),
            constraints: None,
        };
        let opts = IssueOptions {
            facts: Some(terms("x", &["net"], None)),
            ..Default::default()
        };
        let token = issue(&swearer, swearer.did(), &[cap], 3600, &opts).unwrap();
        let rev = RevocationSet::new();
        let err = admit(&token, &rev).unwrap_err();
        assert!(
            err.contains("oath/uphold") || err.contains("sworn oath"),
            "a token without oath/uphold is not a sworn oath: {err}"
        );
    }

    #[test]
    fn token_without_fct_is_denied() {
        let swearer = Keypair::generate();
        let cap = Capability {
            can: OATH_UPHOLD_CAN.to_string(),
            with: "agent:self:abc".to_string(),
            constraints: None,
        };
        let token = issue(&swearer, swearer.did(), &[cap], 3600, &IssueOptions::default()).unwrap();
        let rev = RevocationSet::new();
        let err = admit(&token, &rev).unwrap_err();
        assert!(err.contains("no fct") || err.contains("terms"), "got: {err}");
    }

    // ---- (c) raw JSON still works, signed:false ---------------------------

    #[test]
    fn raw_json_admits_unsigned() {
        let rev = RevocationSet::new();
        let admitted = admit(reference_json(), &rev).expect("raw JSON admits");
        assert!(!admitted.signed, "raw JSON is unsigned");
        assert!(!admitted.ulysses);
        assert!(admitted.swearer.is_none());
        let fct = enforce(&admitted, &["net".to_string()], 3600).unwrap();
        assert_eq!(fct["signed"], false);
        assert_eq!(fct["ulysses"], false);
        assert_eq!(fct["sworn_by"], Value::Null);
        assert_eq!(fct["oath"], "I serve the spawner's intent, stay within my caps, and do not exfiltrate.");
    }

    // ---- (d) caps/ttl bounds still enforced on verified terms -------------

    #[test]
    fn token_caps_violation_denied() {
        let swearer = Keypair::generate();
        let token = mint_oath_token(&swearer, swearer.did(), terms("x", &["net"], Some(3600)));
        let rev = RevocationSet::new();
        let admitted = admit(&token, &rev).unwrap();
        // request a cap outside the verified terms -> DENY
        let err = enforce(&admitted, &["fs".to_string()], 60).unwrap_err();
        assert!(err.contains("exceed the oath"), "got: {err}");
    }

    #[test]
    fn token_ttl_violation_denied() {
        let swearer = Keypair::generate();
        let token = mint_oath_token(&swearer, swearer.did(), terms("x", &["net"], Some(3600)));
        let rev = RevocationSet::new();
        let admitted = admit(&token, &rev).unwrap();
        let err = enforce(&admitted, &["net".to_string()], 7200).unwrap_err();
        assert!(err.contains("ttl"), "got: {err}");
        assert!(err.contains("3600"), "should name the ceiling: {err}");
    }

    #[test]
    fn revoked_swearer_denied() {
        let swearer = Keypair::generate();
        let token = mint_oath_token(&swearer, swearer.did(), terms("x", &["net"], None));
        let mut rev = RevocationSet::new();
        rev.revoke_issuer(swearer.did());
        let err = admit(&token, &rev).unwrap_err();
        assert!(
            err.contains("invalid") || err.contains("revoked"),
            "a revoked swearer must be denied: {err}"
        );
    }

    // ---- (e) oath-subset attenuation down a delegation tree ----------------

    /// A co-signed oath where the child's permitted caps are a SUBSET of the
    /// parent's (and its ttl ceiling is within the parent's): admits, the
    /// ENFORCED terms are the LEAF (tightest), and the grant fct records the
    /// chain depth + the imposing parent.
    #[test]
    fn cosigned_attenuated_child_admits_with_chain_proof() {
        let parent = Keypair::generate(); // spawner imposes
        let child = Keypair::generate(); // agent accepts
        // Parent permits [net, fs] for up to 3600s; child accepts the tighter
        // [net] for up to 1800s -> a proper attenuation.
        let leaf = mint_cosigned_chain(
            &parent,
            &child,
            terms("serve the spawner, stay bounded", &["net", "fs"], Some(3600)),
            terms("I bind myself to net only", &["net"], Some(1800)),
        );

        let rev = RevocationSet::new();
        let admitted = admit(&leaf, &rev).expect("attenuated co-signed oath admits");
        assert!(admitted.signed);
        // Ulysses is a leaf-shape flag (iss == aud); here the child accepts by
        // self-binding, so the leaf is Ulysses-shaped. What makes attenuation
        // apply is the chain DEPTH (> 1), not the Ulysses flag.
        assert_eq!(admitted.chain_depth, Some(2));
        assert_eq!(admitted.imposed_by.as_deref(), Some(parent.did()));
        // The swearer is the leaf's iss (the child who actually accepted).
        assert_eq!(admitted.swearer.as_deref(), Some(child.did()));
        // The ENFORCED terms are the LEAF (tightest): the child is held to net
        // only and ttl <= 1800. Requesting fs (which the PARENT permits) is
        // denied because the leaf does not.
        assert!(
            enforce(&admitted, &["fs".to_string()], 60).is_err(),
            "child is bound to the leaf (tightest) terms, not the parent's"
        );
        assert!(enforce(&admitted, &["net".to_string()], 1800).is_ok());
        assert!(
            enforce(&admitted, &["net".to_string()], 1801).is_err(),
            "ttl bound is the leaf ceiling (1800), not the parent's (3600)"
        );

        // The grant fct carries the chain-depth proof metadata.
        let fct = enforce(&admitted, &["net".to_string()], 1800).unwrap();
        assert_eq!(fct["oath_chain_depth"], 2);
        assert_eq!(fct["imposed_by"], parent.did());
        assert_eq!(fct["signed"], true);
        assert_eq!(fct["sworn_by"], child.did());
        assert_eq!(fct["oath"], "I bind myself to net only");
        assert_eq!(fct["max_caps"][0], "net");
    }

    /// A co-signed oath where the child tries to permit MORE caps than the
    /// parent imposed: DENIED with an oath-escalation message naming the caps.
    #[test]
    fn cosigned_caps_escalation_denied() {
        let parent = Keypair::generate();
        let child = Keypair::generate();
        // Parent permits [net]; child tries to permit [net, fs] -> escalation.
        let leaf = mint_cosigned_chain(
            &parent,
            &child,
            terms("net only", &["net"], Some(3600)),
            terms("I want net AND fs", &["net", "fs"], Some(3600)),
        );

        let rev = RevocationSet::new();
        let err = admit(&leaf, &rev).unwrap_err();
        assert!(err.contains("admission denied"), "got: {err}");
        assert!(err.contains("oath escalation"), "got: {err}");
        assert!(
            err.contains("child oath permits"),
            "must name the child terms: {err}"
        );
        assert!(err.contains("fs"), "must name the offending cap: {err}");
        assert!(
            err.contains("parent oath"),
            "must name the parent terms: {err}"
        );
    }

    /// A co-signed oath where the child's ttl ceiling exceeds the parent's: a ttl
    /// escalation is DENIED. An unbounded child under a bounded parent is also
    /// DENIED.
    #[test]
    fn cosigned_ttl_escalation_denied() {
        let parent = Keypair::generate();
        let child = Keypair::generate();
        // Child ttl ceiling 7200 > parent's 3600 -> escalation.
        let leaf = mint_cosigned_chain(
            &parent,
            &child,
            terms("bounded to 1h", &["net"], Some(3600)),
            terms("I want 2h", &["net"], Some(7200)),
        );
        let rev = RevocationSet::new();
        let err = admit(&leaf, &rev).unwrap_err();
        assert!(err.contains("oath escalation"), "got: {err}");
        assert!(err.contains("ttl"), "got: {err}");
        assert!(err.contains("3600"), "must name the parent ceiling: {err}");

        // Child leaves ttl unbounded under a bounded parent -> DENIED (cannot
        // silently widen the ttl).
        let leaf2 = mint_cosigned_chain(
            &parent,
            &child,
            terms("bounded to 1h", &["net"], Some(3600)),
            terms("I leave ttl open", &["net"], None),
        );
        let err2 = admit(&leaf2, &rev).unwrap_err();
        assert!(err2.contains("oath escalation"), "got: {err2}");
        assert!(
            err2.contains("unbounded"),
            "unbounded child under bounded parent must be denied: {err2}"
        );
    }

    /// A single-link Ulysses token has nothing to attenuate against: it still
    /// admits unchanged, with chain_depth 1 and NO chain-proof metadata in fct.
    #[test]
    fn single_ulysses_token_admits_unchanged_no_chain_proof() {
        let swearer = Keypair::generate();
        let token = mint_oath_token(
            &swearer,
            swearer.did(),
            terms("I bind myself", &["net", "fs"], Some(3600)),
        );
        let rev = RevocationSet::new();
        let admitted = admit(&token, &rev).expect("Ulysses token still admits");
        assert!(admitted.signed);
        assert!(admitted.ulysses);
        assert_eq!(admitted.chain_depth, Some(1));
        assert!(admitted.imposed_by.is_none());

        let fct = enforce(&admitted, &["net".to_string()], 3600).unwrap();
        assert_eq!(fct["ulysses"], true);
        assert_eq!(fct["signed"], true);
        // No chain-depth proof metadata for a single-link token.
        assert!(
            fct.get("oath_chain_depth").is_none(),
            "single-link token must not carry oath_chain_depth"
        );
        assert!(
            fct.get("imposed_by").is_none(),
            "single-link token must not carry imposed_by"
        );
    }
}
